import Foundation

enum APIError: Error {
    case invalidURL
    case invalidResponse
    case serverError(Int)
    case decodingError
}

final class NetworkClient {
    static let shared = NetworkClient()

    private let session: URLSession

    private init() {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: configuration)
    }

    func fetchAPIStatus() async throws -> String {
        guard let url = URL(string: "https://api.example.com/status") else {
            throw APIError.invalidURL
        }

        let (data, response) = try await session.data(from: url)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard 200..<300 ~= httpResponse.statusCode else {
            throw APIError.serverError(httpResponse.statusCode)
        }

        return String(data: data, encoding: .utf8) ?? "No content"
    }

    func fetchLegacyStatus() async throws -> String {
        guard let url = URL(string: "http://legacy.internal/status") else {
            throw APIError.invalidURL
        }

        let (data, response) = try await session.data(from: url)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard 200..<300 ~= httpResponse.statusCode else {
            throw APIError.serverError(httpResponse.statusCode)
        }

        return String(data: data, encoding: .utf8) ?? "No content"
    }
}

import SwiftUI

struct ContentView: View {
    @State private var apiResponse = "Not loaded"
    @State private var legacyResponse = "Not loaded"
    @State private var isLoading = false
    @State private var errorMessage: String?

    var body: some View {
        NavigationView {
            VStack(alignment: .leading, spacing: 16) {
                Group {
                    Text("API Server")
                        .font(.headline)
                    Text(apiResponse)
                        .font(.body)
                        .foregroundColor(.secondary)
                }

                Group {
                    Text("Legacy System")
                        .font(.headline)
                    Text(legacyResponse)
                        .font(.body)
                        .foregroundColor(.secondary)
                }

                if let errorMessage {
                    Text(errorMessage)
                        .foregroundColor(.red)
                }

                Button(isLoading ? "Loading..." : "Load Data") {
                    Task {
                        await loadData()
                    }
                }
                .disabled(isLoading)

                Spacer()
            }
            .padding()
            .navigationTitle("Connectivity Test")
        }
    }

    @MainActor
    private func loadData() async {
        isLoading = true
        errorMessage = nil

        do {
            async let api = NetworkClient.shared.fetchAPIStatus()
            async let legacy = NetworkClient.shared.fetchLegacyStatus()

            apiResponse = try await api
            legacyResponse = try await legacy
        } catch {
            errorMessage = error.localizedDescription
        }

        isLoading = false
    }
}